const rows = $input.all().map(i => i.json);

// helper: get eh first existing key
const pick = (obj, keys) => {
  for (const k of keys) if (k in obj && obj[k] != null && obj[k] !== '') return obj[k];
  return undefined;
};

const categories = {};
for (const row of rows) {
  const category = pick(row, ['Catégorie', 'Category']) || 'Non classé';
  const question = pick(row, ['Question', 'Please write your request', 'Please write your re', 'Request', 'Message']) || '(no question)';
  const from     = pick(row, ['Nom', 'Name', 'Full Name', 'Adresse e-mail', 'Email Address', 'Email']) || 'Anonymous';

  if (!categories[category]) categories[category] = [];
  categories[category].push({ question, from });
}

let html = `<h2>📬 Questions of the day received (${rows.length})</h2>`;
for (const [cat, items] of Object.entries(categories)) {
  html += `<h3>${cat} (${items.length})</h3><ul>`;
  for (const it of items) {
    html += `<li><strong>${it.from}</strong><br>${it.question}</li>`;
  }
  html += `</ul>`;
}

return [{ json: { html, count: rows.length } }];
